<?php $formatDate=static function($v){$t=strtotime((string)$v);return $t?date('d.m.Y H:i',$t):(string)$v;}; ?>
<div class="page-head forms-page-head"><div><p class="eyebrow">Історія</p><h1>Відповіді форм</h1><p class="page-subtitle"><?= count($items) ?> останніх відповідей із збереженою структурою полів.</p></div><a class="button secondary" href="<?= url('/admin/forms') ?>"><span class="mdi mdi-arrow-left"></span><span>До форм</span></a></div>
<form method="get" class="submission-filter"><label>Показати відповіді<select name="form_id" onchange="this.form.submit()"><option value="0">Усі форми</option><?php foreach($forms as $form): ?><option value="<?= e((string)$form['id']) ?>" <?= selected((string)$formId,(string)$form['id']) ?>><?= e($form['title']) ?></option><?php endforeach; ?></select></label></form>
<div class="list-panel"><div class="table-scroll"><table><thead><tr><th>Отримано</th><th>Форма</th><th>Контакт</th><th>Відповіді</th></tr></thead><tbody>
<?php foreach($items as $item): $answers=json_decode((string)$item['answers_json'],true)?:[];$schema=json_decode((string)$item['schema_snapshot_json'],true)?:[];$labels=array_column($schema,'label','id'); ?><tr><td><strong><?= e($formatDate($item['created_at'])) ?></strong><div><span class="status <?= $item['status']==='new'?'warn':'' ?>"><?= $item['status']==='new'?'Нова':e($item['status']) ?></span></div></td><td><?= e($item['form_title']) ?><div class="meta">Версія <?= e((string)$item['form_version']) ?></div></td><td><?php if(!empty($item['submitter_email'])): ?><a href="mailto:<?= e($item['submitter_email']) ?>"><?= e($item['submitter_email']) ?></a><?php else: ?><span class="meta">Не вказано</span><?php endif; ?></td><td><div class="submission-answer-list"><?php foreach($answers as $key=>$value): ?><div><strong><?= e($labels[$key]??$key) ?></strong><span><?= e(is_array($value)?implode(', ',$value):((string)$value!==''?(string)$value:'—')) ?></span></div><?php endforeach; ?></div></td></tr><?php endforeach; ?>
</tbody></table></div><?php if(!$items): ?><div class="empty-state"><span class="mdi mdi-inbox-outline"></span><h2>Відповідей ще немає</h2><p>Нові надсилання з’являться тут автоматично.</p></div><?php endif; ?></div>
